mapper.select:
SELECT p.performance_id, p.employee_id, e.name AS employee_name, p.eval_date, p.score, p.grade, p.comment, p.evaluate_date, p.created_at FROM performance_info p LEFT JOIN employee_info e ON p.employee_id = e.employee_id
AND p.employee_id = #{employeeId}
AND e.name LIKE CONCAT('%', #{employeeName}, '%')
AND p.grade = #{grade}
AND p.eval_date >= #{startDate}
AND p.eval_date <= #{endDate}
ORDER BY p.eval_date DESC, p.score DESC, p.created_at DESC LIMIT #{pageSize} OFFSET #{pageNum}

SELECT COUNT(*)
FROM performance_info p
LEFT JOIN employee_info e ON p.employee_id = e.employee_id


        AND p.employee_id = #{employeeId}


        AND e.name LIKE CONCAT('%', #{employeeName}, '%')


        AND p.grade = #{grade}


        AND p.eval_date >= #{startDate}


        AND p.eval_date <= #{endDate}

SELECT ROW_NUMBER() OVER (ORDER BY p.score DESC) AS ranking, p.employee_id, e.name AS employee_name, p.eval_date, p.score, p.grade FROM performance_info p LEFT JOIN employee_info e ON p.employee_id = e.employee_id
AND p.eval_date = #{evalDate}
ORDER BY p.score DESC
